<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Maze Bots</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0d0d1a;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 20px;
  }
  #hud {
    display: flex;
    align-items: center;
    gap: 24px;
    margin-bottom: 16px;
    padding: 12px 24px;
    background: #1a1a2e;
    border-radius: 8px;
    border: 1px solid #333;
  }
  #hud span {
    font-size: 18px;
    font-weight: 600;
  }
  #completed { color: #4caf50; }
  #timer { color: #2196f3; }
  #reset {
    padding: 8px 20px;
    font-size: 16px;
    font-weight: 600;
    background: #e74c3c;
    color: white;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s;
  }
  #reset:hover { background: #c0392b; }
  #maze {
    border: 2px solid #444;
    border-radius: 4px;
    background: #1a1a2e;
  }
</style>
</head>
<body>
  <div id="hud">
    <span id="completed">Completed: 0</span>
    <span id="timer">Time: 0.0s</span>
    <button id="reset">Reset</button>
  </div>
  <canvas id="maze"></canvas>

<script>
(function() {
  const COLS = 20;
  const ROWS = 20;
  const CELL_SIZE = 25;
  const CANVAS_SIZE = COLS * CELL_SIZE;
  const NUM_BOTS = 24;
  const MAX_DELAY = 150;
  const TIME_PER_TICK = 16.67;

  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');
  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetBtn = document.getElementById('reset');

  canvas.width = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;

  let grid = null;
  let bots = [];
  let completedCount = 0;
  let totalTicks = 0;
  let running = false;
  let animFrameId = null;

  const spawn = { x: 0, y: 0 };
  const exit = { x: COLS - 1, y: ROWS - 1 };

  function generateMaze() {
    const g = [];
    for (let y = 0; y < ROWS; y++) {
      g[y] = [];
      for (let x = 0; x < COLS; x++) {
        g[y][x] = { top: true, right: true, bottom: true, left: true, visited: false };
      }
    }

    const stack = [];
    const start = { x: 0, y: 0 };
    g[0][0].visited = true;
    stack.push(start);

    while (stack.length > 0) {
      const current = stack[stack.length - 1];
      const neighbors = [];

      if (current.y > 0 && !g[current.y - 1][current.x].visited) {
        neighbors.push({ x: current.x, y: current.y - 1, dir: 'top' });
      }
      if (current.x < COLS - 1 && !g[current.y][current.x + 1].visited) {
        neighbors.push({ x: current.x + 1, y: current.y, dir: 'right' });
      }
      if (current.y < ROWS - 1 && !g[current.y + 1][current.x].visited) {
        neighbors.push({ x: current.x, y: current.y + 1, dir: 'bottom' });
      }
      if (current.x > 0 && !g[current.y][current.x - 1].visited) {
        neighbors.push({ x: current.x - 1, y: current.y, dir: 'left' });
      }

      if (neighbors.length > 0) {
        const next = neighbors[Math.floor(Math.random() * neighbors.length)];
        if (next.dir === 'top') {
          g[current.y][current.x].top = false;
          g[next.y][next.x].bottom = false;
        } else if (next.dir === 'right') {
          g[current.y][current.x].right = false;
          g[next.y][next.x].left = false;
        } else if (next.dir === 'bottom') {
          g[current.y][current.x].bottom = false;
          g[next.y][next.x].top = false;
        } else if (next.dir === 'left') {
          g[current.y][current.x].left = false;
          g[next.y][next.x].right = false;
        }
        g[next.y][next.x].visited = true;
        stack.push(next);
      } else {
        stack.pop();
      }
    }

    return g;
  }

  function bfs(start, end) {
    const visited = Array.from({ length: ROWS }, () => Array(COLS).fill(false));
    const parent = Array.from({ length: ROWS }, () => Array(COLS).fill(null));
    const queue = [start];
    visited[start.y][start.x] = true;

    while (queue.length > 0) {
      const current = queue.shift();
      if (current.x === end.x && current.y === end.y) {
        const path = [];
        let node = current;
        while (node) {
          path.unshift(node);
          node = parent[node.y][node.x];
        }
        return path;
      }

      const cell = grid[current.y][current.x];
      const dirs = [
        { dx: 0, dy: -1, wall: 'top' },
        { dx: 1, dy: 0, wall: 'right' },
        { dx: 0, dy: 1, wall: 'bottom' },
        { dx: -1, dy: 0, wall: 'left' }
      ];

      for (const d of dirs) {
        const nx = current.x + d.dx;
        const ny = current.y + d.dy;
        if (nx >= 0 && nx < COLS && ny >= 0 && ny < ROWS && !visited[ny][nx] && !cell[d.wall]) {
          visited[ny][nx] = true;
          parent[ny][nx] = current;
          queue.push({ x: nx, y: ny });
        }
      }
    }

    return null;
  }

  function createBots() {
    const newBots = [];
    for (let i = 0; i < NUM_BOTS; i++) {
      const path = bfs(spawn, exit);
      newBots.push({
        x: spawn.x,
        y: spawn.y,
        path: path,
        pathIndex: 0,
        started: false,
        completed: false,
        delay: Math.floor(Math.random() * MAX_DELAY),
        color: `hsl(${(i * 360 / NUM_BOTS) + Math.random() * 30}, 75%, 60%)`
      });
    }
    return newBots;
  }

  function tick(n) {
    for (let step = 0; step < n; step++) {
      for (const bot of bots) {
        if (bot.completed) continue;
        if (!bot.started) {
          bot.delay--;
          if (bot.delay <= 0) {
            bot.started = true;
          }
          continue;
        }
        bot.pathIndex++;
        if (bot.pathIndex >= bot.path.length) {
          bot.completed = true;
          completedCount++;
        } else {
          bot.x = bot.path[bot.pathIndex].x;
          bot.y = bot.path[bot.pathIndex].y;
        }
      }
    }
    totalTicks += n;
    updateHUD();
  }

  function updateHUD() {
    completedEl.textContent = 'Completed: ' + completedCount;
    timerEl.textContent = 'Time: ' + (totalTicks * TIME_PER_TICK / 1000).toFixed(1) + 's';
  }

  function render() {
    ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    ctx.fillStyle = '#1a1a2e';
    ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    ctx.fillStyle = 'rgba(33, 150, 243, 0.3)';
    ctx.fillRect(spawn.x * CELL_SIZE + 1, spawn.y * CELL_SIZE + 1, CELL_SIZE - 2, CELL_SIZE - 2);

    ctx.fillStyle = 'rgba(76, 175, 80, 0.3)';
    ctx.fillRect(exit.x * CELL_SIZE + 1, exit.y * CELL_SIZE + 1, CELL_SIZE - 2, CELL_SIZE - 2);

    ctx.strokeStyle = '#555';
    ctx.lineWidth = 2;
    ctx.lineCap = 'round';

    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        const cell = grid[y][x];
        const px = x * CELL_SIZE;
        const py = y * CELL_SIZE;

        if (cell.top) {
          ctx.beginPath();
          ctx.moveTo(px, py);
          ctx.lineTo(px + CELL_SIZE, py);
          ctx.stroke();
        }
        if (cell.right) {
          ctx.beginPath();
          ctx.moveTo(px + CELL_SIZE, py);
          ctx.lineTo(px + CELL_SIZE, py + CELL_SIZE);
          ctx.stroke();
        }
        if (cell.bottom) {
          ctx.beginPath();
          ctx.moveTo(px, py + CELL_SIZE);
          ctx.lineTo(px + CELL_SIZE, py + CELL_SIZE);
          ctx.stroke();
        }
        if (cell.left) {
          ctx.beginPath();
          ctx.moveTo(px, py);
          ctx.lineTo(px, py + CELL_SIZE);
          ctx.stroke();
        }
      }
    }

    ctx.fillStyle = '#4caf50';
    ctx.fillRect(exit.x * CELL_SIZE + 4, exit.y * CELL_SIZE + 4, CELL_SIZE - 8, CELL_SIZE - 8);

    for (const bot of bots) {
      if (bot.completed) continue;
      ctx.fillStyle = bot.color;
      ctx.beginPath();
      ctx.arc(
        bot.x * CELL_SIZE + CELL_SIZE / 2,
        bot.y * CELL_SIZE + CELL_SIZE / 2,
        CELL_SIZE / 3.5,
        0,
        Math.PI * 2
      );
      ctx.fill();
    }
  }

  function animate() {
    if (!running) return;
    tick(1);
    render();
    animFrameId = requestAnimationFrame(animate);
  }

  function startGame() {
    grid = generateMaze();
    bots = createBots();
    completedCount = 0;
    totalTicks = 0;
    running = true;
    updateHUD();
    render();
    animate();
  }

  function resetGame() {
    running = false;
    if (animFrameId) {
      cancelAnimationFrame(animFrameId);
      animFrameId = null;
    }
    startGame();
  }

  startGame();

  resetBtn.addEventListener('click', resetGame);

  window.game = {
    get bots() { return bots; },
    get completed() { return completedCount; },
    get elapsedMs() { return totalTicks * TIME_PER_TICK; },
    tick: tick,
    reset: resetGame
  };
})();
</script>
</body>
</html>
